text:
$footer-breakpoint-tablet: 62.5em;
$footer-breakpoint-mobile: 40em;

.root {
  --docs-footer-height: 400px;

  @mixin smaller-than $footer-breakpoint-tablet {
    --docs-footer-height: 520px;
  }

  @mixin smaller-than $footer-breakpoint-mobile {
    --docs-footer-height: 380px;
  }
}

.spacer {
  height: var(--docs-footer-height);
}

.wrapper {
  position: fixed;
  bottom: 0;
  left: 0;
  right: 0;
  height: var(--docs-footer-height);
  background-color: var(--mantine-color-body);

  &[data-with-navbar] {
    padding-inline-start: calc(
      var(--docs-navbar-width) + var(--mantine-spacing-md) * 2 + var(--docs-inline-spacing)
    );
    padding-inline-end: calc(var(--mantine-spacing-md) * 2);

    @mixin smaller-than 1520px {
      padding-inline-start: calc(var(--docs-navbar-width) + var(--docs-inline-spacing));
    }

    @mixin smaller-than $docs-mdx-breakpoint {
      padding-inline-start: var(--docs-inline-spacing);
      padding-inline-end: var(--docs-inline-spacing);
    }
  }
}

.inner {
  padding-top: calc(var(--mantine-spacing-xl) * 2);
  padding-bottom: calc(var(--mantine-spacing-xl) * 2);
  display: flex;
  justify-content: space-between;

  @mixin smaller-than $footer-breakpoint-tablet {
    flex-direction: column;
  }

  @mixin smaller-than $footer-breakpoint-mobile {
    padding-bottom: var(--mantine-spacing-md);
  }
}

.logoSection {
  max-width: 300px;

  @mixin smaller-than $footer-breakpoint-tablet {
    margin-bottom: var(--mantine-spacing-xl);
  }

  @mixin smaller-than $footer-breakpoint-mobile {
    margin-bottom: 0;
  }
}

.description {
  margin-top: var(--mantine-spacing-xs);
  color: var(--mantine-color-dimmed);
}

.afterFooter {
  border-top: 1px solid light-dark(var(--mantine-color-gray-2), var(--mantine-color-dark-4));
  padding-top: var(--mantine-spacing-md);
}

.afterFooterNote {
  &,
  & a {
    color: var(--mantine-color-bright);
  }
}

.groups {
  display: flex;

  @mixin smaller-than $footer-breakpoint-mobile {
    display: none;
  }
}

.social {
  display: flex;

  @mixin smaller-than $footer-breakpoint-mobile {
    display: block;
  }
}

.socialButton {
  &:last-of-type {
    margin-inline-start: var(--mantine-spacing-md);
  }

  @mixin smaller-than $footer-breakpoint-mobile {
    width: 100%;
    margin-left: 0 !important;
    margin-right: 0 !important;
    margin-top: var(--mantine-spacing-sm);
  }
}

@keyframes slide {
  0% {
    transform: translate3d(0, 0, 0);
  }

  100% {
    transform: translate3d(0, -2076px, 0); /* The image width */
  }
}

.root {
  height: 692px;
  background-color: var(--mantine-color-body);
  position: relative;
  overflow: hidden;

  @mixin dark {
    background-color: var(--mantine-color-dark-7);
  }

  @mixin smaller-than $mantine-breakpoint-md {
    height: auto;
  }
}

.container {
  position: relative;
  padding-top: 200px;
  padding-bottom: var(--hp-block-spacing);

  @mixin smaller-than $mantine-breakpoint-md {
    padding-top: 80px;
  }
}

.image {
  height: calc(2052px * 3);
  position: absolute;
  width: 1000px;
  background-size: contain;
  z-index: 1;
  right: 0;
  top: 0;
  background-repeat: repeat-y;
  animation: slide 120s linear infinite;

  @mixin smaller-than $mantine-breakpoint-md {
    display: none;
  }
}

.main {
  position: relative;
  z-index: 3;
}

.overlay {
  position: absolute;
  inset: 0;
  z-index: 2;
  background: linear-gradient(-95deg, rgba(255, 255, 255, 0.5) 0%, rgba(255, 255, 255, 1) 60%);

  @mixin dark {
    background: linear-gradient(
      -95deg,
      alpha(var(--mantine-color-dark-7), 0.5) 0%,
      var(--mantine-color-dark-7) 60%
    );
  }
}

.action {
  height: 60px;
  width: 220px;
  border-radius: var(--mantine-radius-md);
  font-size: var(--mantine-font-size-lg);
  padding-inline: var(--mantine-spacing-lg);
  font-weight: 600;
  padding-top: 3px;
  border: 0;
  border-bottom: 3px solid transparent;

  transition:
    box-shadow 100ms ease,
    transform 100ms ease;

  @mixin hover {
    box-shadow: var(--mantine-shadow-md);
    transform: translateY(-1px) scale(1.01);
  }

  &[data-get-started] {
    background: var(--hp-primary-bg);
    box-shadow: var(--hp-primary-shadow);
    border-bottom: var(--hp-primary-border);
  }

  &[data-github] {
    background-color: var(--mantine-color-dark-7);
    color: var(--mantine-color-white);
    font-weight: 600;

    @mixin hover {
      background-color: var(--mantine-color-black);
    }

    @mixin dark {
      border-color: var(--mantine-color-dark-5);
      background-color: var(--mantine-color-gray-1);
      color: var(--mantine-color-black);
    }
  }

  @mixin smaller-than $mantine-breakpoint-xs {
    width: 100%;
  }
}

.actions {
  display: flex;
  gap: var(--mantine-spacing-lg);
  margin-top: 40px;

  @mixin smaller-than $mantine-breakpoint-xs {
    flex-direction: column;
  }
}

@keyframes scaleIn {
  from {
    opacity: 0;
    transform: scale(0.8);
  }
}

@keyframes scaleOut {
  to {
    opacity: 0;
    transform: scale(0);
  }
}

.TooltipPopup {
  font-family: 'IBM Plex Sans', sans-serif;
  background: black;
  color: white;
  padding: 4px 6px;
  border-radius: 4px;
  font-size: 95%;
  cursor: default;
  transform-origin: var(--transform-origin);

  &[data-instant] {
    transition-duration: 0s !important;
    animation-duration: 0s !important;
  }

  &[data-type='css-animation'] {
    animation: scaleIn 0.2s forwards;

    &[data-ending-style] {
      animation: scaleOut 0.2s forwards;
    }
  }

  &[data-type='css-animation-keep-mounted'] {
    animation: scaleIn 0.2s forwards;

    &[data-ending-style] {
      animation: scaleOut 0.2s forwards;
    }
  }

  &[data-type='css-transition'] {
    transition-property: opacity, transform;
    transition-duration: 0.2s;

    &[data-ending-style] {
      opacity: 0;
      transform: scale(0);
    }

    &[data-starting-style] {
      opacity: 0;
      transform: scale(0.8);
    }
  }

  &[data-type='css-transition-keep-mounted'] {
    transition-property: opacity, transform;
    transition-duration: 0.2s;

    &[data-ending-style] {
      opacity: 0;
      transform: scale(0);
    }

    &[data-starting-style] {
      opacity: 0;
      transform: scale(0.8);
    }
  }

  &[data-type='css-transition-starting-style'] {
    transition-property: opacity, transform, visibility;
    transition-duration: 0.2s;

    @starting-style {
      opacity: 0;
      transform: scale(0.8);
    }

    &[data-ending-style] {
      opacity: 0;
      transform: scale(0);
    }
  }
}

.AnchorButton {
  border: none;
  background: #0072e6;
  color: white;
  padding: 8px 16px;
  border-radius: 4px;
  font-size: 16px;

  &:focus-visible {
    outline: 2px solid #3399ff;
    outline-offset: 2px;
  }

  &:hover,
  &[data-popup-open] {
    background: #004c99;
  }
}

@keyframes rt-fade-in {
  from {
    opacity: 0;
  }
  to {
    opacity: 1;
  }
}

@keyframes rt-fade-out {
  from {
    opacity: 1;
  }
  to {
    opacity: 0;
  }
}

@keyframes rt-slide-from-top {
  from {
    transform: translateY(4px) scale(0.97);
  }
  to {
    transform: translateY(0) scale(1);
  }
}

@keyframes rt-slide-to-top {
  from {
    transform: translateY(0) scale(1);
  }
  to {
    transform: translateY(4px) scale(0.97);
  }
}

@keyframes rt-slide-from-bottom {
  from {
    transform: translateY(-4px) scale(0.97);
  }
  to {
    transform: translateY(0) scale(1);
  }
}

@keyframes rt-slide-to-bottom {
  from {
    transform: translateY(0) scale(1);
  }
  to {
    transform: translateY(-4px) scale(0.97);
  }
}

@keyframes rt-slide-from-left {
  from {
    transform: translateX(4px) scale(0.97);
  }
  to {
    transform: translateX(0) scale(1);
  }
}

@keyframes rt-slide-to-left {
  from {
    transform: translateX(0) scale(1);
  }
  to {
    transform: translateX(4px) scale(0.97);
  }
}

@keyframes rt-slide-from-right {
  from {
    transform: translateX(-4px) scale(0.97);
  }
  to {
    transform: translateX(0) scale(1);
  }
}

@keyframes rt-slide-to-right {
  from {
    transform: translateX(0) scale(1);
  }
  to {
    transform: translateX(-4px) scale(0.97);
  }
}

@media (prefers-reduced-motion: no-preference) {
  .rt-PopperContent {
    animation-timing-function: cubic-bezier(0.16, 1, 0.3, 1);

    &:where([data-state='open']) {
      animation-duration: 160ms;

      &:where([data-side='top']) {
        animation-name: rt-slide-from-top, rt-fade-in;
      }
      &:where([data-side='bottom']) {
        animation-name: rt-slide-from-bottom, rt-fade-in;
      }
      &:where([data-side='left']) {
        animation-name: rt-slide-from-left, rt-fade-in;
      }
      &:where([data-side='right']) {
        animation-name: rt-slide-from-right, rt-fade-in;
      }
    }

    &:where([data-state='closed']) {
      animation-duration: 100ms;

      &:where([data-side='top']) {
        animation-name: rt-slide-to-top, rt-fade-out;
      }
      &:where([data-side='bottom']) {
        animation-name: rt-slide-to-bottom, rt-fade-out;
      }
      &:where([data-side='left']) {
        animation-name: rt-slide-to-left, rt-fade-out;
      }
      &:where([data-side='right']) {
        animation-name: rt-slide-to-right, rt-fade-out;
      }
    }
  }
}
